import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a ratio?", a: "A ratio compares two or more quantities. For example, a ratio of 2:3 means there are 2 parts of one quantity for every 3 parts of another." },
  { q: "How do you simplify a ratio?", a: "Divide each part of the ratio by the greatest common factor. For example, 12:18 simplifies to 2:3 because both values divide by 6." },
  { q: "What is a proportion?", a: "A proportion states that two ratios are equal, such as 2:3 = 8:12. Proportions can be solved by cross multiplication." },
  { q: "How do you find a missing value in a proportion?", a: "Set the ratios equal and cross multiply. For a:b = c:x, the missing value is x = (b x c) / a." },
  { q: "What is the difference between ratio and fraction?", a: "A fraction usually represents part of a whole, while a ratio compares quantities. Ratios can be written with colons, words, or fractions depending on the context." },
];

type Mode = "simplify" | "missing" | "scale";
const gcd = (a: number, b: number): number => b === 0 ? Math.abs(a) : gcd(b, a % b);
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

export default function RatioCalculator() {
  const [mode, setMode] = useState<Mode>("simplify");
  const [a, setA] = useState(12);
  const [b, setB] = useState(18);
  const [c, setC] = useState(8);
  const [scale, setScale] = useState(3);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (mode === "simplify") {
      const divisor = gcd(Math.round(a), Math.round(b));
      if (!divisor) return { label: "Simplified Ratio", value: "Invalid", step: "Enter nonzero ratio values." };
      return { label: "Simplified Ratio", value: `${a / divisor}:${b / divisor}`, step: `GCF(${a}, ${b}) = ${divisor}. Divide both parts by ${divisor}: ${a}:${b} = ${a / divisor}:${b / divisor}.` };
    }
    if (mode === "missing") {
      if (a === 0) return { label: "Missing Value", value: "Invalid", step: "The first ratio value cannot be zero." };
      const x = (b * c) / a;
      return { label: "Missing Value", value: fmt(x), step: `Solve ${a}:${b} = ${c}:x. Cross multiply: ${a}x = ${b} x ${c}. x = ${b * c} / ${a} = ${fmt(x)}.` };
    }
    return { label: "Scaled Ratio", value: `${fmt(a * scale)}:${fmt(b * scale)}`, step: `Scale ${a}:${b} by ${scale}. New ratio = (${a} x ${scale}):(${b} x ${scale}) = ${fmt(a * scale)}:${fmt(b * scale)}.` };
  }, [mode, a, b, c, scale]);

  return (
    <>
      <SEOHead title="Free Ratio Calculator Online - Simplify Ratios and Solve Proportions Instantly | CalcHive" description="Free online ratio calculator. Simplify any ratio, find missing values in proportions and scale ratios up or down instantly. 100% free for students and everyone, no signup required." canonical="/ratio-calculator" keywords="free ratio calculator, ratio simplifier free online, proportion calculator free, simplify ratio free, ratio to fraction calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Ratio Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free ratio calculator to simplify ratio free, solve proportions, and scale ratios up or down.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="simplify">Simplify ratio</option><option value="missing">Find missing value</option><option value="scale">Scale ratio</option></select></div>
            <div><label htmlFor="a" className="text-sm font-semibold text-foreground block mb-2">First value</label><input id="a" type="number" inputMode="decimal" value={a} onChange={(event) => setA(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="b" className="text-sm font-semibold text-foreground block mb-2">Second value</label><input id="b" type="number" inputMode="decimal" value={b} onChange={(event) => setB(Number(event.target.value))} className={inputClass} /></div>
            {mode === "missing" && <div><label htmlFor="c" className="text-sm font-semibold text-foreground block mb-2">Third value</label><input id="c" type="number" inputMode="decimal" value={c} onChange={(event) => setC(Number(event.target.value))} className={inputClass} /></div>}
            {mode === "scale" && <div><label htmlFor="scale" className="text-sm font-semibold text-foreground block mb-2">Scale factor</label><input id="scale" type="number" inputMode="decimal" value={scale} onChange={(event) => setScale(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${a}-${b}-${c}-${scale}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight" data-testid="result-ratio">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Simplify Any Ratio for Free</h2><p className="text-muted-foreground leading-relaxed">Enter the ratio values and this ratio simplifier free online tool divides both parts by their greatest common factor.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Solve Proportions and Find Missing Values</h2><p className="text-muted-foreground leading-relaxed">Use proportion calculator free mode to cross multiply and solve for the missing value in two equal ratios.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Ratio and Proportion Tool for Students and Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this ratio to fraction calculator free online for math homework, recipes, scaling designs, and everyday comparisons.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/ratio-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


